    this->rect_bg = lv_obj_create(this->scr);
    lv_obj_remove_style_all(this->rect_bg);
    lv_obj_set_size(this->rect_bg, LV_PCT(100), LV_PCT(100));
    lv_obj_set_align(this->rect_bg, LV_ALIGN_TOP_MID);
